.header-wrapper {
    font-family: 'Roboto', Arial, sans-serif;
    width: 100%;
    height: 100%;
    box-sizing: border-box;
    display: flex;
    align-items: center;
    gap: 10px;
    background-color: #24272A;
    border-radius: 8px;
    padding: 10px 16px;
    position: relative
}

/* ===== ICON CONTAINER ===== */
.header-icon-container {
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    width: 22px;
    height: 22px
}

.header-icon-container .material-icons {
    font-size: 22px;
    color: #EE7623
}

.header-icon-container svg {
    width: 22px;
    height: 22px
}

.header-icon-container img {
    width: 22px;
    height: 22px;
    object-fit: contain
}

/* ===== SELECTOR CONTAINER ===== */
.selector-container {
    flex: 1;
    min-width: 0;
    position: relative
}

/* ===== SELECTED DISPLAY (trigger) ===== */
.selected-display {
    display: flex;
    align-items: center;
    gap: 8px;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 6px;
    transition: background-color 0.2s ease
}

.selected-display:hover {
    background-color: rgba(255, 255, 255, 0.08)
}

.selected-label {
    color: #ffffff;
    font-size: clamp(14px, 3vw, 18px);
    font-weight: 500;
    flex: 1;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap
}

.dropdown-arrow {
    font-size: 20px;
    color: #9EA1A2;
    flex-shrink: 0;
    transition: transform 0.25s ease, color 0.2s ease
}

.dropdown-arrow.open {
    transform: rotate(180deg);
    color: #EE7623
}

.selected-display:hover .dropdown-arrow {
    color: #EE7623
}

/* ===== LAST ACTIVITY ===== */
.last-activity {
    font-size: 10px;
    color: #9EA1A2;
    position: absolute;
    bottom: 4px;
    right: 12px;
    white-space: nowrap
}

