self.onInit = function() {
    var settings = self.ctx.settings || {};
    var $scope = self.ctx.$scope;

    // Settings with defaults
    var customIconUrl      = (settings.customIconUrl      || '').trim();
    var iconName           = settings.iconName            || 'flash_on';
    var iconColor          = settings.iconColor           || '#EE7623';   // global fill
    var specificPathIds    = (settings.specificPathIds    || '').trim();
    var specificPathColor  = settings.specificPathColor   || '';
    $scope.noDeviceText      = settings.noDeviceText      || 'Seleccionar Dispositivo';
    $scope.noDataText        = settings.noDataText        || 'Sin datos';
    $scope.lastActivityLabel = settings.lastActivityLabel || 'Última telemetría:';
    $scope.searchPlaceholder = settings.searchPlaceholder || 'Nombre o etiqueta...';
    var systemFilter = settings.systemFilter || 'energy';

    var SVG_SHAPES = 'path,circle,rect,polygon,line,polyline,ellipse';
    var svgLoaded  = false;   // true once inline SVG is in the container

    // State
    $scope.dropdownOpen = false;
    $scope.loading = false;
    $scope.hasDevice = false;
    $scope.selectedLabel = $scope.noDeviceText;
    $scope.lastActivityStr = $scope.noDataText;
    $scope.searchText = '';
    $scope.devices = [];
    $scope.filteredDevices = [];
    var devicesLoaded = false;

    var currentDeviceId = null;

    // ============================================================
    // RECOVER DEVICE FROM STATE PARAMS (survives state changes)
    // ============================================================
    function recoverFromStateParams() {
        try {
            var stateParams = self.ctx.stateController.getStateParams();
            if (stateParams && stateParams.device_selection) {
                var sel = stateParams.device_selection;
                var entityId = sel.entityId;
                var id = entityId ? (entityId.id || entityId) : null;
                if (id) {
                    currentDeviceId = id;
                    $scope.selectedLabel = sel.entityLabel || sel.entityName || $scope.noDeviceText;
                    $scope.hasDevice = true;
                    // Mark selected in cached device list
                    $scope.devices.forEach(function(d) {
                        var dId = d.id ? d.id.id : d.id;
                        d.isSelected = (dId === id);
                    });
                }
            }
        } catch(e) { /* ignore */ }
    }
    var http = self.ctx.$injector.get(self.ctx.servicesMap.get('http'));

    // ============================================================
    // DROPDOWN PANEL — rendered in document.body to avoid overflow
    // ============================================================
    var dropdownEl = null;
    var listContainerEl = null;

    function createDropdownPanel() {
        if (dropdownEl) return;

        dropdownEl = document.createElement('div');
        dropdownEl.id = 'hs-dropdown-' + Date.now();
        dropdownEl.style.cssText = [
            'position:fixed',
            'min-width:280px',
            'max-height:360px',
            'background-color:#2C2F33',
            'border-radius:8px',
            'box-shadow:0 8px 24px rgba(0,0,0,0.45),0 2px 8px rgba(0,0,0,0.25)',
            'border:1px solid rgba(255,255,255,0.08)',
            'z-index:9999',
            'display:flex',
            'flex-direction:column',
            'overflow:hidden',
            'font-family:Roboto,Arial,sans-serif',
            'animation:hsDropdownSlideIn 0.2s ease'
        ].join(';');

        // Inject keyframes if not already present
        if (!document.getElementById('hs-dropdown-keyframes')) {
            var style = document.createElement('style');
            style.id = 'hs-dropdown-keyframes';
            style.textContent = [
                '@keyframes hsDropdownSlideIn{from{opacity:0;transform:translateY(-8px)}to{opacity:1;transform:translateY(0)}}',
                '.hs-search-wrap{display:flex;align-items:center;gap:8px;padding:10px 12px;border-bottom:1px solid rgba(255,255,255,0.08);flex-shrink:0}',
                '.hs-search-wrap .material-icons{font-size:18px;color:#9EA1A2;flex-shrink:0}',
                '.hs-search-input{flex:1;background:transparent;border:none;outline:none;color:#fff;font-size:14px;font-family:Roboto,Arial,sans-serif}',
                '.hs-search-input::placeholder{color:#6B6E72}',
                '.hs-loading{display:flex;align-items:center;justify-content:center;gap:10px;padding:24px 12px;color:#9EA1A2;font-size:13px}',
                '.hs-spinner{width:18px;height:18px;border:2px solid rgba(255,255,255,0.15);border-top-color:#EE7623;border-radius:50%;animation:hsSpin .8s linear infinite}',
                '@keyframes hsSpin{to{transform:rotate(360deg)}}',
                '.hs-list{overflow-y:auto;flex:1;max-height:300px}',
                '.hs-list::-webkit-scrollbar{width:6px}',
                '.hs-list::-webkit-scrollbar-track{background:transparent}',
                '.hs-list::-webkit-scrollbar-thumb{background-color:rgba(255,255,255,0.15);border-radius:3px}',
                '.hs-list::-webkit-scrollbar-thumb:hover{background-color:rgba(255,255,255,0.25)}',
                '.hs-item{display:flex;align-items:center;gap:12px;padding:10px 12px;cursor:pointer;transition:background-color .15s ease;border-left:3px solid transparent}',
                '.hs-item:hover{background-color:rgba(255,255,255,0.06);border-left-color:#EE7623}',
                '.hs-item.active{background-color:rgba(238,118,35,0.1);border-left-color:#EE7623}',
                '.hs-item-icon{font-size:20px;color:#EE7623;flex-shrink:0}',
                '.hs-item-info{flex:1;min-width:0}',
                '.hs-item-name{font-size:14px;font-weight:500;color:#fff;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}',
                '.hs-item-activity{font-size:11px;color:#6B6E72;margin-top:1px}',
                '.hs-check{font-size:18px;color:#EE7623;flex-shrink:0}',
                '.hs-empty{display:flex;flex-direction:column;align-items:center;gap:6px;padding:24px 12px;color:#6B6E72;font-size:13px}',
                '.hs-empty .material-icons{font-size:32px;color:#4A4D51}'
            ].join('\n');
            document.head.appendChild(style);
        }

        // Search bar
        var searchWrap = document.createElement('div');
        searchWrap.className = 'hs-search-wrap';
        searchWrap.innerHTML = '<span class="material-icons">search</span>';

        var searchInput = document.createElement('input');
        searchInput.type = 'text';
        searchInput.className = 'hs-search-input';
        searchInput.placeholder = $scope.searchPlaceholder;
        searchInput.addEventListener('input', function() {
            $scope.searchText = searchInput.value;
            filterDeviceList();
            renderList();
        });
        searchWrap.appendChild(searchInput);
        dropdownEl.appendChild(searchWrap);

        // List container
        listContainerEl = document.createElement('div');
        listContainerEl.className = 'hs-list';
        dropdownEl.appendChild(listContainerEl);

        document.body.appendChild(dropdownEl);
        positionDropdown();

        // Focus the search input
        setTimeout(function() { searchInput.focus(); }, 50);
    }

    function positionDropdown() {
        if (!dropdownEl) return;
        var trigger = document.getElementById('selectorContainer');
        if (!trigger) return;
        var rect = trigger.getBoundingClientRect();

        dropdownEl.style.left = rect.left + 'px';
        dropdownEl.style.top = (rect.bottom + 6) + 'px';
        dropdownEl.style.width = Math.max(rect.width, 280) + 'px';
    }

    function destroyDropdownPanel() {
        if (dropdownEl && dropdownEl.parentNode) {
            dropdownEl.parentNode.removeChild(dropdownEl);
        }
        dropdownEl = null;
        listContainerEl = null;
    }

    function renderList() {
        if (!listContainerEl) return;
        listContainerEl.innerHTML = '';

        if ($scope.loading) {
            listContainerEl.innerHTML =
                '<div class="hs-loading">' +
                    '<span class="hs-spinner"></span>' +
                    '<span>Cargando...</span>' +
                '</div>';
            return;
        }

        var list = $scope.filteredDevices;
        if (!list || list.length === 0) {
            listContainerEl.innerHTML =
                '<div class="hs-empty">' +
                    '<span class="material-icons">search_off</span>' +
                    '<span>No se encontraron dispositivos</span>' +
                '</div>';
            return;
        }

        list.forEach(function(device) {
            var item = document.createElement('div');
            item.className = 'hs-item' + (device.isSelected ? ' active' : '');

            var checkHtml = device.isSelected
                ? '<span class="material-icons hs-check">check_circle</span>'
                : '';

            item.innerHTML =
                buildIconHtml('hs-item-icon') +
                '<div class="hs-item-info">' +
                    '<div class="hs-item-name">' + escapeHtml(device.displayName) + '</div>' +
                    '<div class="hs-item-activity">' + escapeHtml($scope.lastActivityLabel + ' ' + device.lastActivity) + '</div>' +
                '</div>' +
                checkHtml;

            item.addEventListener('click', function() {
                $scope.selectDevice(device);
            });

            listContainerEl.appendChild(item);
        });
    }

    function escapeHtml(text) {
        var div = document.createElement('div');
        div.appendChild(document.createTextNode(text));
        return div.innerHTML;
    }

    // ============================================================
    // ICON — SVG box pattern
    // ============================================================

    // Apply global colour + specific-path overrides to the SVG in #hs-icon-container
    function applySvgStyles() {
        var container = document.getElementById('hs-icon-container');
        if (!container || !svgLoaded) return;

        // Global fill: all shapes
        if (iconColor) {
            container.querySelectorAll(SVG_SHAPES).forEach(function(el) {
                el.setAttribute('fill', iconColor);
                el.style.fill = iconColor;
            });
        }

        // Specific path overrides by ID (comma-separated)
        if (specificPathIds && specificPathColor) {
            specificPathIds.split(',').forEach(function(rawId) {
                var id = rawId.trim();
                if (!id) return;
                var el = container.querySelector('#' + id);
                if (el) {
                    el.setAttribute('fill', specificPathColor);
                    el.style.fill = specificPathColor;
                }
            });
        }
    }

    // Load and render the header icon
    function loadSvg() {
        var container = document.getElementById('hs-icon-container');
        if (!container) return;
        container.innerHTML = '';
        svgLoaded = false;

        if (customIconUrl.length === 0) {
            // Material icon fallback
            var span = document.createElement('span');
            span.className = 'material-icons';
            span.style.fontSize = '22px';
            span.style.color = iconColor;
            span.textContent = iconName;
            container.appendChild(span);
            return;
        }

        if (customIconUrl.indexOf('<svg') !== -1) {
            // Raw SVG code
            container.innerHTML = customIconUrl;
            var svgEl = container.querySelector('svg');
            if (svgEl) { svgEl.style.width = '22px'; svgEl.style.height = '22px'; }
            svgLoaded = true;
            applySvgStyles();
        } else {
            // URL: load inline via XHR
            loadSvgFromUrl(customIconUrl);
        }
    }

    function loadSvgFromUrl(url) {
        var container = document.getElementById('hs-icon-container');
        var xhr = new XMLHttpRequest();
        xhr.open('GET', url, true);
        xhr.onload = function() {
            if (!container) return;
            if (xhr.status === 200 && xhr.responseText.indexOf('<svg') !== -1) {
                container.innerHTML = xhr.responseText;
                var svgEl = container.querySelector('svg');
                if (svgEl) { svgEl.style.width = '22px'; svgEl.style.height = '22px'; }
                svgLoaded = true;
                applySvgStyles();
            } else {
                container.innerHTML = '<img src="' + escapeHtml(url) + '" style="width:22px;height:22px;object-fit:contain" />';
            }
        };
        xhr.onerror = function() {
            if (container) {
                container.innerHTML = '<img src="' + escapeHtml(url) + '" style="width:22px;height:22px;object-fit:contain" />';
            }
        };
        xhr.send();
    }

    // Synchronous HTML string for dropdown item rows
    // SVG URLs fall back to <img> since we can't do async here
    function buildIconHtml(cssClass) {
        var cls = cssClass || '';
        if (customIconUrl.length > 0) {
            if (customIconUrl.indexOf('<svg') !== -1) {
                return '<span class="' + cls + '" style="display:flex;align-items:center;width:20px;height:20px;flex-shrink:0">' +
                           customIconUrl +
                       '</span>';
            }
            return '<img src="' + escapeHtml(customIconUrl) + '" class="' + cls + '" style="width:20px;height:20px;object-fit:contain;flex-shrink:0" />';
        }
        return '<span class="material-icons ' + cls + '" style="color:' + escapeHtml(iconColor) + '">' + escapeHtml(iconName) + '</span>';
    }

    // ============================================================
    // CLOSE ON OUTSIDE CLICK
    // ============================================================
    var closeHandler = function(event) {
        if (!$scope.dropdownOpen) return;
        var trigger = document.getElementById('selectorContainer');
        if (trigger && trigger.contains(event.target)) return;
        if (dropdownEl && dropdownEl.contains(event.target)) return;

        $scope.dropdownOpen = false;
        destroyDropdownPanel();
        self.ctx.detectChanges();
    };
    document.addEventListener('mousedown', closeHandler, true);

    // Reposition on scroll/resize
    var repositionHandler = function() {
        if ($scope.dropdownOpen) positionDropdown();
    };
    window.addEventListener('scroll', repositionHandler, true);
    window.addEventListener('resize', repositionHandler);

    // ============================================================
    // TOGGLE
    // ============================================================
    $scope.toggleDropdown = function() {
        $scope.dropdownOpen = !$scope.dropdownOpen;
        if ($scope.dropdownOpen) {
            $scope.searchText = '';
            filterDeviceList();
            createDropdownPanel();
            renderList();
        } else {
            destroyDropdownPanel();
        }
        self.ctx.detectChanges();
    };

    // ============================================================
    // SEARCH FILTER
    // ============================================================
    function filterDeviceList() {
        if (!$scope.searchText || $scope.searchText.trim() === '') {
            $scope.filteredDevices = $scope.devices;
        } else {
            var search = $scope.searchText.toLowerCase();
            $scope.filteredDevices = $scope.devices.filter(function(d) {
                var name = (d.name || '').toLowerCase();
                var label = (d.label || '').toLowerCase();
                return name.includes(search) || label.includes(search);
            });
        }
    }

    function formatDate(timestamp) {
        if (!timestamp) return $scope.noDataText;
        return new Date(timestamp).toLocaleString('es-CL');
    }

    // ============================================================
    // LOAD DEVICES
    // ============================================================
    function loadDevices() {
        if (devicesLoaded) return;
        $scope.loading = true;
        $scope.devices = [];
        $scope.filteredDevices = [];

        http.get('/api/auth/user').subscribe(
            function(user) {
                var customerId = user.customerId ? user.customerId.id : null;
                var authority = user.authority || '';
                var nullCustomer = '13814000-1dd2-11b2-8080-808080808080';

                var url;
                if (authority === 'CUSTOMER_USER' && customerId && customerId !== nullCustomer) {
                    url = '/api/customer/' + customerId + '/devices?pageSize=500&page=0&sortProperty=label&sortOrder=ASC';
                } else {
                    url = '/api/tenant/devices?pageSize=500&page=0&sortProperty=label&sortOrder=ASC';
                }

                http.get(url).subscribe(
                    function(result) {
                        var allDevices = result.data || result || [];
                        if (!Array.isArray(allDevices)) {
                            finishLoading([]);
                            return;
                        }
                        if (systemFilter && systemFilter.trim() !== '') {
                            filterBySystem(allDevices, systemFilter.trim());
                        } else {
                            enrichDevices(allDevices);
                        }
                    },
                    function() { finishLoading([]); }
                );
            },
            function() { finishLoading([]); }
        );
    }

    function filterBySystem(devices, filterValue) {
        var filtered = [];
        var pending = devices.length;

        if (pending === 0) {
            finishLoading([]);
            return;
        }

        devices.forEach(function(device) {
            var deviceId = device.id ? device.id.id : device.id;
            var attrUrl = '/api/plugins/telemetry/DEVICE/' + deviceId + '/values/attributes/SERVER_SCOPE?keys=system';
            http.get(attrUrl).subscribe(
                function(attrs) {
                    attrs = attrs || [];
                    var systemAttr = attrs.find(function(a) { return a.key === 'system'; });
                    if (systemAttr && systemAttr.value === filterValue) {
                        filtered.push(device);
                    }
                    pending--;
                    if (pending === 0) enrichDevices(filtered);
                },
                function() {
                    pending--;
                    if (pending === 0) enrichDevices(filtered);
                }
            );
        });
    }

    function enrichDevices(devices) {
        var pending = devices.length;

        if (pending === 0) {
            finishLoading([]);
            return;
        }

        var enriched = devices.map(function(device) {
            var deviceId = device.id ? device.id.id : device.id;
            return {
                id: device.id,
                name: device.name || '',
                label: device.label || '',
                displayName: device.label || device.name || 'Sin nombre',
                lastActivity: $scope.noDataText,
                isSelected: deviceId === currentDeviceId
            };
        });

        enriched.forEach(function(device) {
            var deviceId = device.id ? device.id.id : device.id;
            var attrUrl = '/api/plugins/telemetry/DEVICE/' + deviceId + '/values/attributes/SERVER_SCOPE?keys=lastActivityTime';
            http.get(attrUrl).subscribe(
                function(attrs) {
                    attrs = attrs || [];
                    var lastAttr = attrs.find(function(a) { return a.key === 'lastActivityTime'; });
                    if (lastAttr && lastAttr.value) {
                        device.lastActivity = formatDate(lastAttr.value);
                    }
                    pending--;
                    if (pending === 0) finishLoading(enriched);
                },
                function() {
                    pending--;
                    if (pending === 0) finishLoading(enriched);
                }
            );
        });
    }

    function finishLoading(devices) {
        $scope.devices = devices;
        devicesLoaded = true;
        filterDeviceList();
        $scope.loading = false;
        renderList();
        self.ctx.detectChanges();
    }

    // ============================================================
    // SELECT DEVICE — stays on current state, only updates params
    // ============================================================
    $scope.selectDevice = function(device) {
        var deviceId = device.id ? device.id.id : device.id;
        var deviceName = device.name || '';
        var deviceLabel = device.label || deviceName;

        currentDeviceId = deviceId;
        $scope.selectedLabel = deviceLabel || deviceName;
        $scope.hasDevice = true;
        $scope.dropdownOpen = false;
        destroyDropdownPanel();

        // Mark selected
        $scope.devices.forEach(function(d) {
            var dId = d.id ? d.id.id : d.id;
            d.isSelected = (dId === deviceId);
        });

        var entityId = { id: deviceId, entityType: 'DEVICE' };

        // Build state params with the selected device
        var stateParams = {
            device_selection: {
                entityId: entityId,
                entityName: deviceName,
                entityLabel: deviceLabel
            }
        };

        // Stay on the current state — only update the entity params
        var currentState = self.ctx.stateController.getStateId();
        self.ctx.stateController.updateState(currentState, stateParams);
        self.ctx.detectChanges();
    };

    // Recover selected device from state params (e.g. after state change)
    recoverFromStateParams();

    // Pre-load devices on init (cached)
    loadDevices();

    // Initial data + render header icon once DOM is ready
    self.onDataUpdated();
    setTimeout(function() { loadSvg(); }, 0);

    // Store cleanup references
    self.ctx.$scope._closeHandler = closeHandler;
    self.ctx.$scope._repositionHandler = repositionHandler;
};

self.onDataUpdated = function() {
    var data = self.ctx.data;
    var $scope = self.ctx.$scope;

    // Always try to recover from state params first
    // (this handles state changes from external buttons)
    try {
        var stateParams = self.ctx.stateController.getStateParams();
        if (stateParams && stateParams.device_selection) {
            var sel = stateParams.device_selection;
            var id = sel.entityId ? (sel.entityId.id || sel.entityId) : null;
            if (id) {
                $scope.selectedLabel = sel.entityLabel || sel.entityName || $scope.noDeviceText;
                $scope.hasDevice = true;
                if (id !== $scope._lastRecoveredId) {
                    $scope._lastRecoveredId = id;
                    // Sync cached list selection
                    $scope.devices.forEach(function(d) {
                        var dId = d.id ? d.id.id : d.id;
                        d.isSelected = (dId === id);
                    });
                }
            }
        }
    } catch(e) { /* ignore */ }

    if (!data || data.length === 0) {
        // If we already recovered from state params, keep it
        if (!$scope.hasDevice) {
            $scope.selectedLabel = $scope.noDeviceText;
        }
        self.ctx.detectChanges();
        return;
    }

    // If no device was recovered from state params, try datasource
    if (!$scope.hasDevice) {
        var entityLabel = data[0].datasource.entityLabel || data[0].datasource.entityName || null;
        $scope.hasDevice = !!(entityLabel && entityLabel !== '' && entityLabel !== 'undefined');
        if ($scope.hasDevice) {
            $scope.selectedLabel = entityLabel;
        } else {
            $scope.selectedLabel = $scope.noDeviceText;
        }
    }

    var lastActivityTime = null;
    for (var i = 0; i < data.length; i++) {
        if (data[i].dataKey.name === 'lastActivityTime' || data[i].dataKey.label === 'lastActivityTime') {
            if (data[i].data && data[i].data.length > 0) {
                lastActivityTime = data[i].data[data[i].data.length - 1][1];
            }
            break;
        }
    }

    if (lastActivityTime) {
        $scope.lastActivityStr = new Date(Number(lastActivityTime)).toLocaleString('es-CL');
    } else {
        $scope.lastActivityStr = $scope.noDataText;
    }

    self.ctx.detectChanges();
};

self.onDestroy = function() {
    // Cleanup dropdown from body
    var dropdowns = document.querySelectorAll('[id^="hs-dropdown-"]');
    dropdowns.forEach(function(el) { el.parentNode.removeChild(el); });

    // Cleanup global style
    var style = document.getElementById('hs-dropdown-keyframes');
    if (style) style.parentNode.removeChild(style);

    // Cleanup event listeners
    if (self.ctx.$scope._closeHandler) {
        document.removeEventListener('mousedown', self.ctx.$scope._closeHandler, true);
    }
    if (self.ctx.$scope._repositionHandler) {
        window.removeEventListener('scroll', self.ctx.$scope._repositionHandler, true);
        window.removeEventListener('resize', self.ctx.$scope._repositionHandler);
    }
};

